// Bicep: apply a CanNotDelete lock to protect production resource groups
// from accidental deletion. Deploy this at subscription scope.

targetScope = 'subscription'

param rgName string
param location string = 'eastus2'

resource rg 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: rgName
  location: location
}

// Lock is deployed INSIDE the RG scope
module lock 'rg-lock.bicep' = {
  name: 'rg-lock'
  scope: rg
  params: { lockName: '${rgName}-nodelete' }
}

// rg-lock.bicep:
// param lockName string
// resource lock 'Microsoft.Authorization/locks@2020-05-01' = {
//   name: lockName
//   properties: { level: 'CanNotDelete', notes: 'Production RG — requires change ticket' }
// }

# lifecycle.prevent_destroy: Terraform refuses to destroy this resource
# Use on production resource groups to guard against terraform destroy

resource "azurerm_resource_group" "prod" {
  name     = "myapp-prod-rg"
  location = "eastus2"

  lifecycle {
    prevent_destroy = true
  }
}

# Running 'terraform destroy' now produces:
# Error: Instance cannot be destroyed
# on main.tf line 1: resource "azurerm_resource_group" "prod" {
# Resource azurerm_resource_group.prod has lifecycle.prevent_destroy set,
# but the plan calls for this resource to be destroyed.

# To override: temporarily remove prevent_destroy = true, then destroy
